import React, { useState, useEffect } from 'react';
import { useSpring, animated } from '@react-spring/web';
import { 
  X,
  ArrowLeft,
  Send,
  ThumbsUp,
  FileText,
  Check
} from 'lucide-react';

const NudgeNotificationSheet = ({ newNudges, onClose, onMarkAsRead }) => {
  const [isVisible, setIsVisible] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const [currentNudgeIndex, setCurrentNudgeIndex] = useState(0);
  const [replyMessage, setReplyMessage] = useState('');
  const [showReschedule, setShowReschedule] = useState(false);
  const [selectedDate, setSelectedDate] = useState('');
  const [selectedTimeRange, setSelectedTimeRange] = useState('');
  const [showSuccess, setShowSuccess] = useState(false);
  const [replies, setReplies] = useState([
    {
      id: 1,
      message: "Sure, I can help with those frontend fixes! When do you need them completed?",
      timestamp: "2:30 PM",
      date: "Today",
      isFromMe: true
    },
    {
      id: 2,
      message: "Great! I'd like to have them done by end of week if possible. Let me know if you need any clarification on the requirements.",
      timestamp: "2:35 PM",
      date: "Today",
      isFromMe: false
    }
  ]);

  // Mostrar automaticamente quando há novos nudges
  useEffect(() => {
    if (newNudges && newNudges.length > 0) {
      setIsVisible(true);
      setCurrentNudgeIndex(0); // Sempre começar com o primeiro nudge
    }
  }, [newNudges]);

  // Animação para o container principal
  const containerAnimation = useSpring({
    transform: isVisible ? 'translateX(0%)' : 'translateX(-100%)',
    opacity: isVisible ? 1 : 0,
    height: isExpanded ? '500px' : '80px',
    config: { tension: 300, friction: 30 }
  });

  // Função para fechar o componente
  const handleClose = () => {
    setIsVisible(false);
    setTimeout(() => {
      onClose();
      setIsExpanded(false);
      setCurrentNudgeIndex(0);
      setReplyMessage('');
      setShowReschedule(false);
      setSelectedDate('');
      setSelectedTimeRange('');
      setShowSuccess(false);
    }, 300);
  };

  // Função para expandir/minimizar
  const toggleExpanded = () => {
    if (!isExpanded) {
      // Ao expandir, marcar o nudge atual como lido
      const currentNudge = newNudges[currentNudgeIndex];
      if (currentNudge) {
        onMarkAsRead(currentNudge.id);
      }
    }
    setIsExpanded(!isExpanded);
  };

  // Função para navegar entre nudges
  const nextNudge = () => {
    if (currentNudgeIndex < newNudges.length - 1) {
      setCurrentNudgeIndex(currentNudgeIndex + 1);
      setReplyMessage('');
      setShowReschedule(false);
    }
  };

  const prevNudge = () => {
    if (currentNudgeIndex > 0) {
      setCurrentNudgeIndex(currentNudgeIndex - 1);
      setReplyMessage('');
      setShowReschedule(false);
    }
  };

  // Função para enviar resposta
  const handleSendReply = () => {
    if (replyMessage.trim()) {
      const newReply = {
        id: replies.length + 1,
        message: replyMessage,
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        date: "Today",
        isFromMe: true
      };
      setReplies([...replies, newReply]);
      setReplyMessage('');
    }
  };

  // Função para "Won't be able"
  const handleWontBeAble = () => {
    setShowReschedule(true);
  };

  // Função para confirmar reagendamento
  const handleConfirmReschedule = () => {
    if (selectedDate && selectedTimeRange) {
      setShowSuccess(true);
      setTimeout(() => {
        setShowSuccess(false);
        setShowReschedule(false);
        setSelectedDate('');
        setSelectedTimeRange('');
        toggleExpanded();
      }, 2000);
    }
  };

  // Função para voltar do reagendamento
  const backFromReschedule = () => {
    setShowReschedule(false);
    setSelectedDate('');
    setSelectedTimeRange('');
  };

  // Obter o nudge atual
  const currentNudge = newNudges && newNudges.length > 0 ? newNudges[currentNudgeIndex] : null;

  if (!newNudges || newNudges.length === 0) {
    return null;
  }

  return (
    <div className="fixed bottom-3 left-6 z-50">
      <animated.div
        style={{
          ...containerAnimation,
          width: '380px'
        }}
        className="bg-neutral-800 border border-neutral-700 shadow-2xl rounded-2xl overflow-hidden"
      >
        <div className="p-4 flex flex-col h-full">
          {!isExpanded ? (
            /* Estado Minimizado */
            <div 
              className="flex items-center justify-between cursor-pointer"
              onClick={toggleExpanded}
            >
              <div className="flex items-center space-x-3">
                {currentNudge && (
                  <>
                    <div className="relative">
                      <img
                        src={currentNudge.sender.avatar}
                        alt={currentNudge.sender.name}
                        className="w-10 h-10 rounded-full"
                      />
                      <div className={`absolute -bottom-0.5 -right-0.5 w-3 h-3 rounded-full border-2 border-neutral-800 ${
                        currentNudge.sender.status === 'online' ? 'bg-green-500' : 
                        currentNudge.sender.status === 'away' ? 'bg-orange-500' : 'bg-gray-500'
                      }`} />
                    </div>
                    <div>
                      <h3 className="text-white font-medium">{currentNudge.sender.name}</h3>
                      <p className="text-neutral-400 text-sm truncate max-w-[200px]">
                        {currentNudge.message}
                      </p>
                    </div>
                  </>
                )}
                {newNudges.length > 1 && (
                  <div className="w-6 h-6 bg-red-500 rounded-full flex items-center justify-center ml-2">
                    <span className="text-white text-xs font-bold">{newNudges.length}</span>
                  </div>
                )}
              </div>
              <div className="flex items-center space-x-2">
                <ArrowLeft className="h-5 w-5 text-gray-400 transform rotate-90" />
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    handleClose();
                  }}
                  className="p-1 text-gray-400 hover:text-white transition-colors"
                >
                  <X className="h-4 w-4" />
                </button>
              </div>
            </div>
          ) : (
            /* Estado Expandido */
            <>
              {/* Header Expandido */}
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center space-x-3">
                  <button
                    onClick={toggleExpanded}
                    className="p-1 text-gray-400 hover:text-white transition-colors"
                  >
                    <ArrowLeft className="h-5 w-5 transform -rotate-90" />
                  </button>
                  {currentNudge && (
                    <>
                      <div className="relative">
                        <img
                          src={currentNudge.sender.avatar}
                          alt={currentNudge.sender.name}
                          className="w-8 h-8 rounded-full"
                        />
                        <div className={`absolute -bottom-0.5 -right-0.5 w-3 h-3 rounded-full border-2 border-neutral-800 ${
                          currentNudge.sender.status === 'online' ? 'bg-green-500' : 
                          currentNudge.sender.status === 'away' ? 'bg-orange-500' : 'bg-gray-500'
                        }`} />
                      </div>
                      <div>
                        <h2 className="text-lg font-semibold text-white">{currentNudge.sender.name}</h2>
                        <p className="text-neutral-400 text-sm">{currentNudge.timestamp}</p>
                      </div>
                    </>
                  )}
                </div>
                <div className="flex items-center space-x-2">
                  {newNudges.length > 1 && (
                    <div className="flex items-center space-x-1">
                      <button
                        onClick={prevNudge}
                        disabled={currentNudgeIndex === 0}
                        className="p-1 text-gray-400 hover:text-white transition-colors disabled:opacity-50"
                      >
                        <ArrowLeft className="h-4 w-4" />
                      </button>
                      <span className="text-neutral-400 text-sm">
                        {currentNudgeIndex + 1}/{newNudges.length}
                      </span>
                      <button
                        onClick={nextNudge}
                        disabled={currentNudgeIndex === newNudges.length - 1}
                        className="p-1 text-gray-400 hover:text-white transition-colors disabled:opacity-50"
                      >
                        <ArrowLeft className="h-4 w-4 transform rotate-180" />
                      </button>
                    </div>
                  )}
                  <button
                    onClick={handleClose}
                    className="p-2 text-gray-400 hover:text-white transition-colors"
                  >
                    <X className="h-5 w-5" />
                  </button>
                </div>
              </div>

              {/* Conteúdo da Mensagem */}
              <div className="flex-1 overflow-hidden">
                {showSuccess ? (
                  <div className="flex-1 flex items-center justify-center">
                    <div className="text-center">
                      <div className="w-16 h-16 bg-green-500 rounded-full flex items-center justify-center mx-auto mb-4">
                        <Check className="h-8 w-8 text-white" />
                      </div>
                      <h3 className="text-lg font-semibold text-white mb-2">Alternative Time Sent!</h3>
                      <p className="text-neutral-400 text-sm">Your alternative time has been sent successfully.</p>
                    </div>
                  </div>
                ) : showReschedule ? (
                  <div className="flex-1 flex flex-col">
                    <div className="flex items-center space-x-3 mb-4">
                      <button
                        onClick={backFromReschedule}
                        className="p-1 text-gray-400 hover:text-white transition-colors"
                      >
                        <ArrowLeft className="h-5 w-5" />
                      </button>
                      <h3 className="text-lg font-semibold text-white">Suggest Alternative Time</h3>
                    </div>

                    <div className="space-y-4 flex-1">
                      <div>
                        <label className="block text-sm font-medium text-neutral-300 mb-2">
                          Select Date
                        </label>
                        <select
                          value={selectedDate}
                          onChange={(e) => setSelectedDate(e.target.value)}
                          className="w-full bg-neutral-700 border border-neutral-600 rounded-lg px-3 py-2 text-white focus:outline-none focus:ring-2 focus:ring-white focus:border-transparent"
                        >
                          <option value="">Choose a date</option>
                          <option value="tomorrow">Tomorrow</option>
                          <option value="next-week">Next Week</option>
                          <option value="next-month">Next Month</option>
                        </select>
                      </div>

                      <div>
                        <label className="block text-sm font-medium text-neutral-300 mb-2">
                          Time Range
                        </label>
                        <select
                          value={selectedTimeRange}
                          onChange={(e) => setSelectedTimeRange(e.target.value)}
                          className="w-full bg-neutral-700 border border-neutral-600 rounded-lg px-3 py-2 text-white focus:outline-none focus:ring-2 focus:ring-white focus:border-transparent"
                        >
                          <option value="">Choose time range</option>
                          <option value="morning">Morning (9:00 - 12:00)</option>
                          <option value="afternoon">Afternoon (13:00 - 17:00)</option>
                          <option value="evening">Evening (18:00 - 20:00)</option>
                        </select>
                      </div>

                      <button
                        onClick={handleConfirmReschedule}
                        disabled={!selectedDate || !selectedTimeRange}
                        className={`w-full h-12 flex items-center justify-center space-x-2 rounded-lg transition-colors ${
                          selectedDate && selectedTimeRange
                            ? 'bg-neutral-800 hover:bg-neutral-700 text-white border border-neutral-600'
                            : 'bg-neutral-700 text-neutral-400 cursor-not-allowed'
                        }`}
                      >
                        <Send className="h-5 w-5" />
                        <span className="font-medium">Send Alternative Time</span>
                      </button>
                    </div>
                  </div>
                ) : (
                  <div className="flex-1 flex flex-col">
                    {/* Mensagem principal */}
                    <div className="bg-neutral-700 rounded-lg p-4 mb-4">
                      <p className="text-white text-sm leading-relaxed">
                        {currentNudge.fullMessage || currentNudge.message}
                      </p>

                      {/* Priority badge */}
                      {currentNudge.priority && (
                        <div className="mt-3">
                          <span className={`inline-flex items-center px-2 py-1 rounded-full text-xs font-medium ${
                            currentNudge.priority === 'high' 
                              ? 'bg-red-500/10 text-red-400 border border-red-500/20' 
                              : currentNudge.priority === 'normal'
                              ? 'bg-blue-500/10 text-blue-400 border border-blue-500/20'
                              : 'bg-gray-500/10 text-gray-400 border border-gray-500/20'
                          }`}>
                            {currentNudge.priority.charAt(0).toUpperCase() + currentNudge.priority.slice(1)} Priority
                          </span>
                        </div>
                      )}

                      {/* Anexos */}
                      {currentNudge.attachments && currentNudge.attachments.length > 0 && (
                        <div className="mt-3 space-y-2">
                          <p className="text-neutral-300 text-xs font-medium">Attachments:</p>
                          {currentNudge.attachments.map((attachment, index) => (
                            <div key={index} className="flex items-center space-x-2 text-neutral-400 text-xs">
                              <FileText className="h-3 w-3" />
                              <span>{attachment}</span>
                            </div>
                          ))}
                        </div>
                      )}
                    </div>

                    {/* Histórico de respostas */}
                    <div className="flex-1 overflow-y-auto mb-4">
                      <div className="space-y-3">
                        {replies.map((reply) => (
                          <div
                            key={reply.id}
                            className={`flex ${reply.isFromMe ? 'justify-end' : 'justify-start'}`}
                          >
                            <div
                              className={`max-w-xs px-3 py-2 rounded-lg text-sm ${
                                reply.isFromMe
                                  ? 'bg-blue-600 text-white'
                                  : 'bg-neutral-700 text-neutral-200'
                              }`}
                            >
                              <p>{reply.message}</p>
                              <p className={`text-xs mt-1 ${
                                reply.isFromMe ? 'text-blue-200' : 'text-neutral-400'
                              }`}>
                                {reply.timestamp}
                              </p>
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>

                    {/* Área de resposta */}
                    <div className="space-y-3">
                      <textarea
                        value={replyMessage}
                        onChange={(e) => setReplyMessage(e.target.value)}
                        placeholder="Type your reply..."
                        className="w-full bg-neutral-700 border border-neutral-600 rounded-lg px-3 py-2 text-white placeholder-neutral-400 focus:outline-none focus:ring-2 focus:ring-white focus:border-transparent resize-none"
                        rows={2}
                      />

                      {/* Botões de ação */}
                      <div className="flex space-x-2">
                        <button
                          onClick={handleSendReply}
                          disabled={!replyMessage.trim()}
                          className={`flex-1 h-10 flex items-center justify-center space-x-2 rounded-lg transition-colors ${
                            replyMessage.trim()
                              ? 'bg-blue-600 hover:bg-blue-700 text-white'
                              : 'bg-neutral-700 text-neutral-400 cursor-not-allowed'
                          }`}
                        >
                          <Send className="h-4 w-4" />
                          <span className="text-sm font-medium">Reply</span>
                        </button>

                        <button
                          onClick={handleWontBeAble}
                          className="flex-1 h-10 flex items-center justify-center space-x-2 bg-neutral-700 hover:bg-neutral-600 text-white rounded-lg transition-colors"
                        >
                          <span className="text-sm font-medium">Won't be able</span>
                        </button>

                        <button className="h-10 w-10 flex items-center justify-center bg-neutral-700 hover:bg-neutral-600 text-white rounded-lg transition-colors">
                          <ThumbsUp className="h-4 w-4" />
                        </button>
                      </div>
                    </div>
                  </div>
                )}
              </div>
            </>
          )}
        </div>
      </animated.div>
    </div>
  );
};

export default NudgeNotificationSheet;
